package params

// ---------------------------------------------------------------------------
// Hunter params — NET_VISIT_PARAM + NET_EXTRA_PARAM
// 8 params: 7 basic (matching SaveForge), 1 advanced (not edited by SaveForge).
// Basic sorted: cooldown, list size, summon cap, search timing pair, area rates pair.
